namespace sv_91fb7985f43c4f6785ef03e0cf4b4054.Auth;

/// <summary>
/// Serializable user info passed from server to WebAssembly via PersistentComponentState.
/// </summary>
public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_91fb7985f43c4f6785ef03e0cf4b4054.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that hardcodes a logged-in user
/// and persists the identity into PersistentComponentState so the WebAssembly
/// runtime can pick it up after interactive handoff.
/// </summary>
public sealed class ServerAuthenticationStateProvider
    : RevalidatingServerAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authStateTask;

    public ServerAuthenticationStateProvider(
        ILoggerFactory loggerFactory,
        PersistentComponentState persistentState)
        : base(loggerFactory)
    {
        _persistentState = persistentState;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);

        AuthenticationStateChanged += state => _authStateTask = state;
    }

    protected override TimeSpan RevalidationInterval => TimeSpan.FromMinutes(30);

    protected override Task<bool> ValidateAuthenticationStateAsync(
        AuthenticationState authenticationState, CancellationToken cancellationToken)
        => Task.FromResult(true);

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);

        return Task.FromResult(new AuthenticationState(user));
    }

    private async Task OnPersistingAsync()
    {
        _authStateTask ??= GetAuthenticationStateAsync();

        var authState = await _authStateTask;
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Email = principal.FindFirstValue(ClaimTypes.Email)!,
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _persistentState.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    void IDisposable.Dispose()
    {
        _subscription.Dispose();
        base.Dispose();
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using sv_91fb7985f43c4f6785ef03e0cf4b4054.Client.Auth;

namespace sv_91fb7985f43c4f6785ef03e0cf4b4054.Client.Auth;

/// <summary>
/// Client-side (WebAssembly) AuthenticationStateProvider that reads the user
/// identity from PersistentComponentState, which was persisted by the server
/// during prerendering.  This ensures the auth state survives the handoff from
/// server to WebAssembly runtime.
/// </summary>
public sealed class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public ClientAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo)
            && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Email),
                new(ClaimTypes.Email, userInfo.Email),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
            _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

